	public record KnownValueSet(AsymmCrypto.AsymmFullKeyPair keypair, String strOg, String strEnc, String strSig, byte[] rawDefOg, byte[] rawEnc, String defEnc, byte[] rawSig, String defSig) {
		@Override
		public String toString() {
			return "<KnownValueSet>";
		}
	}

	private final GlobAsymmCrypto crypto = new GlobAsymmCrypto();

	@BeforeAll
	static void init() {
		Security.addProvider(new BouncyCastleProvider());
		Security.addProvider(new BouncyCastlePQCProvider());
	}

	// Might make it generate a file and load it from there later but oh well
	@Test
	@Disabled("Just a cursed Helper Method to generate the map so I can copy paste it or regenerate it if needed")
	void _generateKnownValues() {
		for (var type : crypto.getTypes()) {
			// Create Keypair
			var keypair = crypto.generateKeypair(type);
			assertThat(keypair).isNotNull();
			String pubSplitKey = keypair.pub().serialize();
			String privSplitKey = keypair.priv().serialize();

			// Encrypt String & Raw & Dev
			String strEnc = crypto.encryptStr(SAMPLE_STR, pubSplitKey);
			String rawEnc = Base64.getEncoder().encodeToString(crypto.encryptRaw(SAMPLE_ARR, pubSplitKey));
			String defEnc = crypto.encrypt(SAMPLE_ARR, pubSplitKey);

			// Sign String & Raw & Dev
			String strSig = crypto.signStr(SAMPLE_STR, privSplitKey);
			String rawSig = Base64.getEncoder().encodeToString(crypto.signRaw(SAMPLE_ARR, privSplitKey));
			String defSig = crypto.sign(SAMPLE_ARR, privSplitKey);

			boolean isLast = type.equals(AsymmCryptoType.values()[AsymmCryptoType.values().length - 1]);

			// Create String that looks like entry
			String entryStr =
					"entry(AsymmCryptoType." + type + ", new KnownValueSet(\n" +
							"\tAsymmCrypto.AsymmFullKeyPair.fromParts(\"" + pubSplitKey + "\", \"" + privSplitKey + "\"),\n" +
							"\tSAMPLE_STR,\n" +
							"\t\"" + strEnc + "\",\n" +
							"\t\"" + strSig + "\",\n" +
							"\tSAMPLE_ARR,\n" +
							"\tBase64.getDecoder().decode(\"" + rawEnc + "\"),\n" +
							"\t\"" + defEnc + "\",\n" +
							"\tBase64.getDecoder().decode(\"" + rawSig + "\"),\n" +
							"\t\"" + defSig + "\"\n" +
							"))" + (isLast ? "" : ",");

			System.out.println(entryStr);
		}
	}

	// Might make it generate a file and load it from there later but oh well
	@Test
	@Disabled("Just a cursed Helper Method to generate the map so I can copy paste it or regenerate it if needed")
	void _generateKnownValuesJS() {
		for (var type : crypto.getTypes()) {
			var keypair = crypto.generateKeypair(type);
			assertThat(keypair).isNotNull();

			String pubSplitKey = keypair.pub().serialize();
			String privSplitKey = keypair.priv().serialize();

			String strEnc = crypto.encryptStr(SAMPLE_STR, pubSplitKey);
			String rawEnc = Base64.getEncoder().encodeToString(crypto.encryptRaw(SAMPLE_ARR, pubSplitKey));
			String defEnc = crypto.encrypt(SAMPLE_ARR, pubSplitKey);

			String strSig = crypto.signStr(SAMPLE_STR, privSplitKey);
			String rawSig = Base64.getEncoder().encodeToString(crypto.signRaw(SAMPLE_ARR, privSplitKey));
			String defSig = crypto.sign(SAMPLE_ARR, privSplitKey);

			boolean isLast = type.equals(AsymmCryptoType.values()[AsymmCryptoType.values().length - 1]);

			String entryStr =
					"    [\n" +
							"        AsymmCryptoType." + type + ",\n" +
							"        {\n" +
							"            keypair: AsymmFullKeyPair.fromSplitKeys(\"" + pubSplitKey + "\", \"" + privSplitKey + "\"),\n" +
							"            strOg: SAMPLE_STR,\n" +
							"            strEnc: \"" + strEnc + "\",\n" +
							"            strSig: \"" + strSig + "\",\n" +
							"            rawDefOg: SAMPLE_ARR,\n" +
							"            rawEnc: b64uDecodeLocal(\"" + rawEnc + "\"),\n" +
							"            defEnc: \"" + defEnc + "\",\n" +
							"            rawSig: b64uDecodeLocal(\"" + rawSig + "\"),\n" +
							"            defSig: \"" + defSig + "\"\n" +
							"        }\n" +
							"    ]" + (isLast ? "" : ",");
			System.out.println(entryStr);
		}
	}
